/// Adversarial: the wire delivers a TAGMSG with from=ALICE (uppercase) and
/// target=BOB (uppercase). The DM buffer was opened earlier as "bob"
/// (lowercase) by an unrelated event. Self-echo routing must hit the
/// existing buffer rather than minting a new "BOB" buffer.
///
/// NOTE: `getOrCreateDM` currently uses case-sensitive name matching, so
/// this test pins down today's behavior. If we later normalize DM buffer
/// names (recommended — would prevent split-buffer bugs), update this test
/// to assert the merged invariant instead of being skipped.
func testSelfEchoMixedCaseTargetCreatesSeparateBuffer_PinsCurrentBehavior() throws {
    let s = makeState()
    _ = seedDMMessage(in: s, peer: "bob", id: "m1", from: me)

    handler(s).handleEvent(reactTagMsg(from: "ALICE", target: "BOB", emoji: "🌀", replyTo: "m1"))

    // Today: routing picks `target = "BOB"`, then `getOrCreateDM("BOB")`
    // creates a *second* buffer because matching is case-sensitive.
    // The reaction lands on the "BOB" buffer's (non-existent) message,
    // so the original "bob" buffer is unchanged.
    //
    // This test exists to make that surface visible. When DM names are
    // canonicalized (lowercased) at intake, this assertion will flip and
    // serve as the regression guard for that fix.
    let bobLower = s.dmBuffers.first(where: { $0.name == "bob" })
    XCTAssertNotNil(bobLower)
    XCTAssertTrue((bobLower?.messages.first?.reactions.isEmpty) ?? false,
                  "today: mixed-case target creates separate buffer; this pins the gap")
}

